// Extract resume text from previous node
const resumeText =
  $input.first().json.text ||
  $input.first().json.data ||
  $input.first().json.content ||
  "";

// Extract job description
const jobDescription =
$('Webhook').first().json.body.job_description
// Clean function (basic normalization)
function cleanText(text) {
  return text
    .replace(/\s+/g, " ")   // remove extra spaces/newlines
    .replace(/\n/g, " ")    // remove line breaks
    .trim();
}

return [
  {
    json: {
      resume: cleanText(resumeText),
      job_description: cleanText(jobDescription)
    }
  }
];

const data = JSON.parse($input.first().json.text)

return [
  {
    json: {
      timestamp: new Date().toISOString(),
      ats_score: data.ats_score,
      score_category: data.score_category,
      confidence: data.confidence,
      matching_requirements: data.matching_requirements.join("|"),
      weak_points: data.weak_points.join(","),
      missing_keywords: data.missing_keywords.join(","),
      mistakes: data.mistakes.join(","),
      suggestions: data.suggestions.join(","),
      improvement_tips: data.improvement_tips.join(",")
    }
  }
];
